#include <iostream>

#include <stdio.h>

#include <math.h>

#include <complex>

#include <algorithm>

#include <vector>

#include <string.h>

using namespace std;





int main()

{

    vector<int> num(100010,0);

    int n;

    cin >> n;

    for(int i=0;i<n;i++){

        int a;

        cin >> a;

        num[a]++;

    }

    int cnt=0;

    for(int i=1;i<100010;i++){

        if(num[i]>1)   cnt+=num[i]-1;

    }

    if(cnt%2==0)     cout << n-cnt << endl;

    else                cout << n-(cnt+1) << endl;

    return 0;

}

