using std::map;



int n, m, x, m1, m2;



map <int, int> p;



int main() {

	scanf("%d", &n);

	for(int i = 0;i < n;i ++) {

		scanf("%d", &x);

		p[x] = 1;

	}

	m = p.size();



	for(map<int, int>::iterator iter1 = p.begin();iter1 != p.end();iter1 ++)

		m1 ++;

	for(auto iter2 : p) 

		m2 ++;

	if(m1 != m || m2 != m)

		puts("ERROR");



	m -= !(m & 1);

	printf("%d", m);

	return 0;

}

